mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.role_id, u.max_storage_bytes, u.used_storage_bytes, u.status, u.create_time, u.update_time, IFNULL(n.note_count, 0) AS noteCount FROM sys_user u LEFT JOIN ( SELECT user_id, COUNT(1) AS note_count FROM biz_note WHERE status != 8 GROUP BY user_id ) n ON n.user_id = u.id
u.id = #{id}
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.status = #{status}
AND u.role_id = #{roleId}
ORDER BY u.id DESC

