mapper.update:
update sys_user set
        used_storage_bytes = GREATEST(used_storage_bytes + #{updateUser.deltaStorageBytes}, 0),
        update_time = now()
where id = #{updateUser.id}
AND  max_storage_bytes >= used_storage_bytes + #{updateUser.deltaStorageBytes}
